create schema if not exists ged;
create table if not exists ged.backup_policy (id uuid primary key, tenant_id uuid null, name text not null, scope text not null check(scope in ('GLOBAL','TENANT')), enabled boolean not null default false, backup_type text not null, frequency text not null check(frequency in ('MANUAL','DAILY','WEEKLY','MONTHLY')), scheduled_at time null, timezone text not null default 'UTC', retention_days int not null default 30 check(retention_days > 0), destination_kind text not null default 'FILESYSTEM', encryption_enabled boolean not null default false, auto_verification_enabled boolean not null default true, auto_restore_test_allowed boolean not null default false, rpo_minutes int null check(rpo_minutes is null or rpo_minutes > 0), rto_minutes int null check(rto_minutes is null or rto_minutes > 0), maintenance_window text null, status text not null default 'DRAFT', created_by text null, updated_by text null, change_justification text null, created_at_utc timestamptz not null default now(), updated_at_utc timestamptz null, reg_status text not null default 'ACTIVE');
create index if not exists ix_backup_policy_tenant_status on ged.backup_policy(tenant_id,status);
create table if not exists ged.backup_job (id uuid primary key, tenant_id uuid null, policy_id uuid null, job_type text not null, status text not null default 'PENDING', progress_percent int not null default 0, current_step text null, requested_by text null, worker_id text null, locked_until_utc timestamptz null, attempts int not null default 0, max_attempts int not null default 3, next_attempt_at_utc timestamptz null, correlation_id text null, payload_json jsonb not null default '{}'::jsonb, created_at_utc timestamptz not null default now(), updated_at_utc timestamptz null);
create index if not exists ix_backup_job_claim on ged.backup_job(status,next_attempt_at_utc,locked_until_utc);
create table if not exists ged.backup_set (id uuid primary key, tenant_id uuid null, policy_id uuid null, backup_type text not null, consistency_mode text not null default 'APPLICATION_ONLINE_MARKER', started_at_utc timestamptz not null default now(), finished_at_utc timestamptz null, status text not null, size_bytes bigint not null default 0, file_count bigint not null default 0, record_count bigint not null default 0, application_version text null, database_version text null, manifest_checksum_sha256 text null, location_masked text null, encryption_enabled boolean not null default false, encryption_key_id text null, rpo_minutes int null, integrity_status text not null default 'PENDING', correlation_id text null, created_at_utc timestamptz not null default now());
create index if not exists ix_backup_set_tenant_status on ged.backup_set(tenant_id,status,integrity_status);
create table if not exists ged.backup_artifact (id uuid primary key, backup_set_id uuid not null references ged.backup_set(id), relative_path text not null, artifact_type text not null, size_bytes bigint not null, sha256 text null, created_at_utc timestamptz not null default now(), unique(backup_set_id, relative_path));
create table if not exists ged.backup_verification (id uuid primary key default gen_random_uuid(), backup_set_id uuid not null references ged.backup_set(id), status text not null check(status in ('PENDING','RUNNING','VALID','INVALID','PARTIAL','NOT_VERIFIABLE','ERROR')), findings_json jsonb not null default '[]'::jsonb, worker_id text null, verified_at_utc timestamptz not null default now());
create table if not exists ged.restore_test (id uuid primary key default gen_random_uuid(), backup_set_id uuid null, tenant_id uuid null, status text not null, target_host_masked text not null, target_database text not null, started_at_utc timestamptz not null default now(), finished_at_utc timestamptz null, rto_seconds int null, justification text not null, correlation_id text null);
create table if not exists ged.restore_test_check (id uuid primary key default gen_random_uuid(), restore_test_id uuid not null references ged.restore_test(id), check_name text not null, status text not null, evidence text null, created_at_utc timestamptz not null default now());
create table if not exists ged.recovery_plan (id uuid primary key default gen_random_uuid(), tenant_id uuid null, name text not null, current_version int not null default 1, status text not null default 'DRAFT', rpo_minutes int null, rto_minutes int null, last_test_at_utc timestamptz null, last_test_result text null, next_review_at_utc timestamptz null, created_at_utc timestamptz not null default now());
create table if not exists ged.recovery_plan_version (id uuid primary key default gen_random_uuid(), recovery_plan_id uuid not null references ged.recovery_plan(id), version int not null, content_json jsonb not null, published_at_utc timestamptz null, created_at_utc timestamptz not null default now(), unique(recovery_plan_id, version));
create table if not exists ged.recovery_test (id uuid primary key default gen_random_uuid(), recovery_plan_id uuid null, tenant_id uuid null, status text not null, evidence_json jsonb not null default '{}'::jsonb, created_at_utc timestamptz not null default now());
create table if not exists ged.recovery_objective_measurement (id uuid primary key default gen_random_uuid(), tenant_id uuid null, source_entity text not null, source_id uuid null, rpo_observed_minutes int null, rto_observed_minutes int null, measured_at_utc timestamptz not null default now());
create table if not exists ged.portability_export (id uuid primary key, tenant_id uuid null, scope text not null, status text not null default 'REQUESTED', requested_by text null, requested_at_utc timestamptz not null default now(), updated_at_utc timestamptz null, finished_at_utc timestamptz null, expires_at_utc timestamptz null, size_bytes bigint not null default 0, package_sha256 text null, package_location_masked text null, idempotency_key text null, correlation_id text null, manifest_json jsonb null, constraint uq_portability_idem unique(tenant_id,idempotency_key));
create index if not exists ix_portability_export_tenant_status on ged.portability_export(tenant_id,status,expires_at_utc);
create table if not exists ged.portability_export_item (id uuid primary key default gen_random_uuid(), export_id uuid not null references ged.portability_export(id), item_type text not null, item_id text null, status text not null, checksum_sha256 text null);
create table if not exists ged.portability_artifact (id uuid primary key default gen_random_uuid(), export_id uuid not null references ged.portability_export(id), relative_path text not null, size_bytes bigint not null, sha256 text not null, unique(export_id, relative_path));
create table if not exists ged.tenant_offboarding (id uuid primary key, tenant_id uuid not null, status text not null, started_at_utc timestamptz not null default now(), effective_at_utc timestamptz not null, access_until_utc timestamptz null, legal_hold boolean not null default false, justification text not null, requested_by text null, portability_export_id uuid null, deletion_approved_at_utc timestamptz null, closed_at_utc timestamptz null);
create index if not exists ix_tenant_offboarding_tenant_status on ged.tenant_offboarding(tenant_id,status);
create table if not exists ged.tenant_offboarding_event (id uuid primary key default gen_random_uuid(), offboarding_id uuid not null references ged.tenant_offboarding(id), event_type text not null, evidence_json jsonb not null default '{}'::jsonb, created_by text null, created_at_utc timestamptz not null default now());
create table if not exists ged.data_retention_hold (id uuid primary key default gen_random_uuid(), tenant_id uuid not null, hold_type text not null, reason text not null, status text not null default 'ACTIVE', starts_at_utc timestamptz not null default now(), ends_at_utc timestamptz null, created_by text null);
create table if not exists ged.operations_worker_heartbeat (worker_id text primary key, host_name text not null, process_id int not null, last_seen_at_utc timestamptz not null, current_job_id uuid null, metadata_json jsonb not null default '{}'::jsonb);
create table if not exists ged.operations_dead_letter (id uuid primary key default gen_random_uuid(), job_id uuid null, job_type text not null, tenant_id uuid null, reason text not null, payload_json jsonb not null default '{}'::jsonb, created_at_utc timestamptz not null default now(), resolved_at_utc timestamptz null);
do $$ begin if to_regclass('ged.schema_migration_history') is not null then insert into ged.schema_migration_history(script_name, notes) values ('2026_07_backup_continuity_portability.sql','Estruturas aditivas para backup, continuidade, recuperação e portabilidade.') on conflict (script_name) do nothing; end if; end $$;

-- Evolução 03.1: campos operacionais aditivos e reaplicáveis para lease, histórico, artefatos reais e portabilidade segura.
alter table if exists ged.backup_job add column if not exists started_at_utc timestamptz null;
alter table if exists ged.backup_job add column if not exists finished_at_utc timestamptz null;
alter table if exists ged.backup_job add column if not exists lease_seconds int not null default 900;
alter table if exists ged.backup_job add constraint ck_backup_job_status_e031 check (status in ('PENDING','CLAIMED','RUNNING','VERIFYING','COMPLETED','RETRY','FAILED','CANCEL_REQUESTED','CANCELLED','DEAD_LETTER')) not valid;
create table if not exists ged.operation_job_event (id uuid primary key default gen_random_uuid(), job_id uuid not null, old_status text null, new_status text not null, worker_id text null, occurred_at_utc timestamptz not null default now(), reason text null, progress_percent int null, correlation_id text null);
create index if not exists ix_operation_job_event_job on ged.operation_job_event(job_id, occurred_at_utc);
alter table if exists ged.backup_set add column if not exists location_internal text null;
alter table if exists ged.backup_set add column if not exists manifest_path_internal text null;
alter table if exists ged.backup_set add column if not exists checksums_path_internal text null;
alter table if exists ged.backup_artifact add column if not exists location_internal text null;
alter table if exists ged.operations_worker_heartbeat add column if not exists started_at_utc timestamptz null;
alter table if exists ged.operations_worker_heartbeat add column if not exists last_success_at_utc timestamptz null;
alter table if exists ged.operations_worker_heartbeat add column if not exists last_error text null;
alter table if exists ged.portability_export add column if not exists package_location_internal text null;
alter table if exists ged.portability_export add column if not exists checkpoint_json jsonb not null default '{}'::jsonb;
alter table if exists ged.portability_export add column if not exists progress_percent int not null default 0;
